BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childName WHERE {
  ?pkg vocab:NamedElement_name "02%20Requirements%20Flow-down%20Views" .
  FILTER(CONTAINS(STR(?pkg), "Black%2520Box%2520Specification"))
  ?pkg vocab:Package_nestedPackage ?child .
  OPTIONAL { ?child vocab:NamedElement_name ?childName }
}
ORDER BY ?childName
